#include "EmitIR.hpp"
#include <llvm/IR/Verifier.h>
#include <llvm/Transforms/Utils/ModuleUtils.h>

#define self (*this)

using namespace asg;

EmitIR::EmitIR(Obj::Mgr& mgr, llvm::LLVMContext& ctx, llvm::StringRef mid)
  : mMgr(mgr)
  , mMod(mid, ctx)
  , mCtx(ctx)
  , mIntTy(llvm::Type::getInt32Ty(ctx))
  , mCurIrb(std::make_unique<llvm::IRBuilder<>>(ctx))
  , mCtorTy(llvm::FunctionType::get(llvm::Type::getVoidTy(ctx), false))
{
}

llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  for (auto&& i : tu->decls)
    self(i);
  return mMod;
}

//==============================================================================
// 类型
//==============================================================================

llvm::Type*
EmitIR::operator()(const Type* type)
{
  // Determine the base scalar LLVM type.
  llvm::Type* base = nullptr;
  switch (type->spec) {
    case Type::Spec::kVoid:
      base = llvm::Type::getVoidTy(mCtx);
      break;
    case Type::Spec::kChar:
      base = llvm::Type::getInt8Ty(mCtx);
      break;
    case Type::Spec::kInt:
      base = llvm::Type::getInt32Ty(mCtx);
      break;
    case Type::Spec::kLong:
    case Type::Spec::kLongLong:
      base = llvm::Type::getInt64Ty(mCtx);
      break;
    default:
      ABORT();
  }

  if (type->texp == nullptr)
    return base;

  return trans_texp(type->texp, type);
}

llvm::Type*
EmitIR::trans_texp(TypeExpr* texp, const Type* whole)
{
  if (auto p = texp->dcst<PointerType>()) {
    // Opaque pointers; the sub type doesn't matter for the LLVM type.
    return llvm::PointerType::get(mCtx, 0);
  }

  if (auto p = texp->dcst<ArrayType>()) {
    Type subt;
    subt.spec = whole->spec;
    subt.qual = whole->qual;
    subt.texp = texp->sub;
    auto subTy = self(&subt);
    // For unsized arrays at the outer level (function parameters), the type
    // decays to a pointer; but here we just emit `[0 x sub]` which is the
    // historical convention. Callers must be careful.
    uint32_t len = p->len == ArrayType::kUnLen ? 0 : p->len;
    return llvm::ArrayType::get(subTy, len);
  }

  if (auto p = texp->dcst<FunctionType>()) {
    Type subt;
    subt.spec = whole->spec;
    subt.qual = whole->qual;
    subt.texp = texp->sub;
    auto retTy = self(&subt);
    std::vector<llvm::Type*> pty;
    for (auto pTy : p->params) {
      auto t = self(pTy);
      // Function parameters of array type decay to pointer.
      if (pTy->texp && (pTy->texp->dcst<ArrayType>() ||
                        pTy->texp->dcst<PointerType>())) {
        t = llvm::PointerType::get(mCtx, 0);
      }
      pty.push_back(t);
    }
    return llvm::FunctionType::get(retTy, std::move(pty), false);
  }

  ABORT();
}

//==============================================================================
// 表达式
//==============================================================================

llvm::Value*
EmitIR::operator()(Expr* obj)
{
  if (auto p = obj->dcst<IntegerLiteral>())
    return self(p);
  if (auto p = obj->dcst<DeclRefExpr>())
    return self(p);
  if (auto p = obj->dcst<ParenExpr>())
    return self(p);
  if (auto p = obj->dcst<UnaryExpr>())
    return self(p);
  if (auto p = obj->dcst<BinaryExpr>())
    return self(p);
  if (auto p = obj->dcst<CallExpr>())
    return self(p);
  if (auto p = obj->dcst<ImplicitCastExpr>())
    return self(p);
  ABORT();
}

llvm::Value*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  // Always return the address (lvalue) so callers can either load or assign.
  // Functions are also "addresses" (Function*).
  auto v = static_cast<llvm::Value*>(obj->decl->any);
  ASSERT(v);
  return v;
}

llvm::Value*
EmitIR::operator()(ParenExpr* obj)
{
  return self(obj->sub);
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto sub = self(obj->sub);

  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;

    case UnaryExpr::kNeg:
      return irb.CreateNeg(sub);

    case UnaryExpr::kNot: {
      // !x : compare against 0, zext to i32 (the result type).
      auto subTy = sub->getType();
      llvm::Value* cmp;
      if (subTy->isIntegerTy(1)) {
        cmp = irb.CreateXor(sub, irb.getInt1(true));
      } else {
        cmp = irb.CreateICmpEQ(sub, llvm::ConstantInt::get(subTy, 0));
      }
      return irb.CreateZExt(cmp, mIntTy);
    }

    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;

  switch (obj->op) {
    case BinaryExpr::kComma: {
      self(obj->lft);
      return self(obj->rht);
    }

    case BinaryExpr::kAssign: {
      auto lAddr = self(obj->lft);
      auto rVal = self(obj->rht);
      irb.CreateStore(rVal, lAddr);
      return rVal;
    }

    case BinaryExpr::kAnd: {
      // Short-circuit &&
      auto lhsBb = irb.GetInsertBlock();
      auto func = lhsBb->getParent();
      auto rhsBb = llvm::BasicBlock::Create(mCtx, "land.rhs", func);
      auto endBb = llvm::BasicBlock::Create(mCtx, "land.end", func);

      auto lhs = emit_cond(obj->lft);
      auto lhsEnd = irb.GetInsertBlock();
      irb.CreateCondBr(lhs, rhsBb, endBb);

      irb.SetInsertPoint(rhsBb);
      auto rhs = emit_cond(obj->rht);
      auto rhsEnd = irb.GetInsertBlock();
      irb.CreateBr(endBb);

      irb.SetInsertPoint(endBb);
      auto phi = irb.CreatePHI(irb.getInt1Ty(), 2);
      phi->addIncoming(irb.getInt1(false), lhsEnd);
      phi->addIncoming(rhs, rhsEnd);
      return irb.CreateZExt(phi, mIntTy);
    }

    case BinaryExpr::kOr: {
      // Short-circuit ||
      auto lhsBb = irb.GetInsertBlock();
      auto func = lhsBb->getParent();
      auto rhsBb = llvm::BasicBlock::Create(mCtx, "lor.rhs", func);
      auto endBb = llvm::BasicBlock::Create(mCtx, "lor.end", func);

      auto lhs = emit_cond(obj->lft);
      auto lhsEnd = irb.GetInsertBlock();
      irb.CreateCondBr(lhs, endBb, rhsBb);

      irb.SetInsertPoint(rhsBb);
      auto rhs = emit_cond(obj->rht);
      auto rhsEnd = irb.GetInsertBlock();
      irb.CreateBr(endBb);

      irb.SetInsertPoint(endBb);
      auto phi = irb.CreatePHI(irb.getInt1Ty(), 2);
      phi->addIncoming(irb.getInt1(true), lhsEnd);
      phi->addIncoming(rhs, rhsEnd);
      return irb.CreateZExt(phi, mIntTy);
    }

    case BinaryExpr::kIndex: {
      // arr[idx] — lvalue, return address.
      // lft is `ArrayToPointerDecay(...)` for plain arrays, or a value directly
      // for raw pointers.  After AOPD, the operand is a ptr; the *original*
      // sub had the array type with [N x ...].  We need the element type and
      // the index calculation.
      auto basePtr = self(obj->lft);
      auto idx = self(obj->rht);

      // Determine element/array type from the lhs's *sub* type before decay.
      // obj->lft is an ImplicitCastExpr(ArrayToPointerDecay) whose sub has
      // array type, OR an expression of pointer-to-array type (after the
      // first index).  In the latter case the lhs's type itself is a pointer
      // to an array (or to a scalar), with `texp` being a pointer whose
      // `sub` is either an ArrayType or null.
      auto lftType = obj->lft->type;
      llvm::Type* elemTy = nullptr;
      if (auto pt = lftType->texp ? lftType->texp->dcst<PointerType>()
                                  : nullptr) {
        // pointer-to-something — the something is the indexed element type.
        Type t;
        t.spec = lftType->spec;
        t.qual = lftType->qual;
        t.texp = pt->sub;
        elemTy = self(&t);
      } else if (auto at = lftType->texp
                             ? lftType->texp->dcst<ArrayType>()
                             : nullptr) {
        // Indexing an array directly (rare — usually decayed first).
        Type t;
        t.spec = lftType->spec;
        t.qual = lftType->qual;
        t.texp = at->sub;
        elemTy = self(&t);
      } else {
        ABORT();
      }

      return irb.CreateInBoundsGEP(elemTy, basePtr, idx);
    }

    default:
      break; // fall through to arithmetic/comparison
  }

  auto lhs = self(obj->lft);
  auto rhs = self(obj->rht);

  switch (obj->op) {
    case BinaryExpr::kAdd:
      return irb.CreateAdd(lhs, rhs);
    case BinaryExpr::kSub:
      return irb.CreateSub(lhs, rhs);
    case BinaryExpr::kMul:
      return irb.CreateMul(lhs, rhs);
    case BinaryExpr::kDiv:
      return irb.CreateSDiv(lhs, rhs);
    case BinaryExpr::kMod:
      return irb.CreateSRem(lhs, rhs);
    case BinaryExpr::kLt:
      return irb.CreateZExt(irb.CreateICmpSLT(lhs, rhs), mIntTy);
    case BinaryExpr::kGt:
      return irb.CreateZExt(irb.CreateICmpSGT(lhs, rhs), mIntTy);
    case BinaryExpr::kLe:
      return irb.CreateZExt(irb.CreateICmpSLE(lhs, rhs), mIntTy);
    case BinaryExpr::kGe:
      return irb.CreateZExt(irb.CreateICmpSGE(lhs, rhs), mIntTy);
    case BinaryExpr::kEq:
      return irb.CreateZExt(irb.CreateICmpEQ(lhs, rhs), mIntTy);
    case BinaryExpr::kNe:
      return irb.CreateZExt(irb.CreateICmpNE(lhs, rhs), mIntTy);
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto& irb = *mCurIrb;

  // The head is normally an ImplicitCastExpr(FunctionToPointerDecay,
  // DeclRefExpr(funcDecl)).  After self() we'd get the Function* (which is a
  // pointer).  We need the function type for the indirect call.
  auto fnPtr = self(obj->head);

  // Reach through the cast to find the original function type.
  Expr* headSrc = obj->head;
  while (auto ic = headSrc->dcst<ImplicitCastExpr>())
    headSrc = ic->sub;

  llvm::FunctionType* fty = nullptr;
  if (auto dr = headSrc->dcst<DeclRefExpr>()) {
    auto fd = dr->decl->dcst<FunctionDecl>();
    ASSERT(fd);
    fty = llvm::dyn_cast<llvm::FunctionType>(self(fd->type));
  } else {
    ABORT();
  }

  std::vector<llvm::Value*> args;
  for (auto&& a : obj->args)
    args.push_back(self(a));

  return irb.CreateCall(fty, fnPtr, args);
}

llvm::Value*
EmitIR::operator()(ImplicitCastExpr* obj)
{
  auto& irb = *mCurIrb;
  auto sub = self(obj->sub);

  switch (obj->kind) {
    case ImplicitCastExpr::kLValueToRValue: {
      auto ty = self(obj->type);
      return irb.CreateLoad(ty, sub);
    }
    case ImplicitCastExpr::kArrayToPointerDecay:
      // The address is already a pointer to the array, which is also a
      // pointer to the first element under opaque pointers.
      return sub;
    case ImplicitCastExpr::kFunctionToPointerDecay:
      return sub;
    case ImplicitCastExpr::kNoOp:
      return sub;
    case ImplicitCastExpr::kIntegralCast: {
      auto dstTy = self(obj->type);
      return irb.CreateIntCast(sub, dstTy, /*signed=*/true);
    }
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::emit_cond(Expr* obj)
{
  auto& irb = *mCurIrb;
  auto v = self(obj);
  if (v->getType()->isIntegerTy(1))
    return v;
  return irb.CreateICmpNE(v, llvm::ConstantInt::get(v->getType(), 0));
}

//==============================================================================
// 初始化器
//==============================================================================

void
EmitIR::emit_init(llvm::Value* addr, const Type* ty, Expr* init)
{
  auto& irb = *mCurIrb;
  auto llty = self(ty);

  // Implicit zero init / empty list for arrays.
  bool isArr = ty->texp && ty->texp->dcst<ArrayType>();

  if (!init || init->dcst<ImplicitInitExpr>()) {
    // Zero-initialize the entire region.
    if (isArr) {
      auto dl = mMod.getDataLayout();
      auto sz = dl.getTypeAllocSize(llty);
      irb.CreateMemSet(addr, irb.getInt8(0),
                       llvm::ConstantInt::get(irb.getInt64Ty(), sz),
                       llvm::MaybeAlign(4));
    } else {
      irb.CreateStore(llvm::ConstantInt::get(llty, 0), addr);
    }
    return;
  }

  if (auto il = init->dcst<InitListExpr>()) {
    if (isArr) {
      // First memset the whole region to zero, then store non-zero elements.
      auto dl = mMod.getDataLayout();
      auto sz = dl.getTypeAllocSize(llty);
      irb.CreateMemSet(addr, irb.getInt8(0),
                       llvm::ConstantInt::get(irb.getInt64Ty(), sz),
                       llvm::MaybeAlign(4));

      auto at = ty->texp->dcst<ArrayType>();
      Type subTy;
      subTy.spec = ty->spec;
      subTy.qual = ty->qual;
      subTy.texp = at->sub;
      bool subIsArr = subTy.texp && subTy.texp->dcst<ArrayType>();

      // Number of elements actually expected.
      uint32_t n = at->len;
      for (uint32_t i = 0; i < il->list.size() && i < n; ++i) {
        // GEP to element i.
        auto elemPtr = irb.CreateInBoundsGEP(
          llty, addr,
          { irb.getInt64(0), irb.getInt64(i) });

        auto sub = il->list[i];
        if (subIsArr) {
          // Sub is array → recurse with the sub-array as init.
          emit_init(elemPtr, &subTy, sub);
        } else {
          // Scalar element.
          if (sub->dcst<ImplicitInitExpr>()) {
            // already zeroed
            continue;
          }
          auto val = self(sub);
          irb.CreateStore(val, elemPtr);
        }
      }
      return;
    }

    // Non-array with brace-init — only meaningful for the scalar in `{x}`.
    if (!il->list.empty()) {
      auto v = self(il->list[0]);
      irb.CreateStore(v, addr);
    } else {
      irb.CreateStore(llvm::ConstantInt::get(llty, 0), addr);
    }
    return;
  }

  // Plain scalar init.
  auto v = self(init);
  irb.CreateStore(v, addr);
}

llvm::Constant*
EmitIR::emit_const(const Type* ty, Expr* init)
{
  auto llty = self(ty);
  if (!init)
    return llvm::Constant::getNullValue(llty);

  if (init->dcst<ImplicitInitExpr>())
    return llvm::Constant::getNullValue(llty);

  if (auto il = init->dcst<InitListExpr>())
    return emit_const_list(llty, ty, il);

  // Scalar — must be a compile-time constant.
  auto v = self(init);
  auto c = llvm::dyn_cast<llvm::Constant>(v);
  ASSERT(c);
  // Some integral casts may produce ConstantExpr; if types differ, fold.
  if (c->getType() != llty) {
    if (auto ci = llvm::dyn_cast<llvm::ConstantInt>(c))
      c = llvm::ConstantInt::get(llty, ci->getSExtValue());
  }
  return c;
}

llvm::Constant*
EmitIR::emit_const_list(llvm::Type* llty, const Type* ty, InitListExpr* il)
{
  if (!llty->isArrayTy()) {
    // Not really expected, but handle defensively.
    if (il->list.empty())
      return llvm::Constant::getNullValue(llty);
    return emit_const(ty, il->list[0]);
  }

  auto at = ty->texp->dcst<ArrayType>();
  Type subTy;
  subTy.spec = ty->spec;
  subTy.qual = ty->qual;
  subTy.texp = at->sub;
  bool subIsArr = subTy.texp && subTy.texp->dcst<ArrayType>();

  auto arrTy = llvm::cast<llvm::ArrayType>(llty);
  auto elemTy = arrTy->getElementType();
  uint32_t n = arrTy->getNumElements();

  std::vector<llvm::Constant*> elems;
  elems.reserve(n);
  for (uint32_t i = 0; i < n; ++i) {
    if (i < il->list.size()) {
      auto sub = il->list[i];
      if (subIsArr) {
        if (auto subIl = sub->dcst<InitListExpr>())
          elems.push_back(emit_const_list(elemTy, &subTy, subIl));
        else
          elems.push_back(llvm::Constant::getNullValue(elemTy));
      } else {
        if (sub->dcst<ImplicitInitExpr>())
          elems.push_back(llvm::Constant::getNullValue(elemTy));
        else
          elems.push_back(emit_const(&subTy, sub));
      }
    } else {
      elems.push_back(llvm::Constant::getNullValue(elemTy));
    }
  }

  return llvm::ConstantArray::get(arrTy, elems);
}

//==============================================================================
// 语句
//==============================================================================

void
EmitIR::operator()(Stmt* obj)
{
  if (auto p = obj->dcst<NullStmt>())
    return;
  if (auto p = obj->dcst<CompoundStmt>())
    return self(p);
  if (auto p = obj->dcst<DeclStmt>())
    return self(p);
  if (auto p = obj->dcst<ExprStmt>())
    return self(p);
  if (auto p = obj->dcst<IfStmt>())
    return self(p);
  if (auto p = obj->dcst<WhileStmt>())
    return self(p);
  if (auto p = obj->dcst<DoStmt>())
    return self(p);
  if (auto p = obj->dcst<BreakStmt>())
    return self(p);
  if (auto p = obj->dcst<ContinueStmt>())
    return self(p);
  if (auto p = obj->dcst<ReturnStmt>())
    return self(p);
  ABORT();
}

void
EmitIR::operator()(CompoundStmt* obj)
{
  for (auto&& stmt : obj->subs)
    self(stmt);
}

void
EmitIR::operator()(DeclStmt* obj)
{
  for (auto&& d : obj->decls)
    self(d);
}

void
EmitIR::operator()(ExprStmt* obj)
{
  if (obj->expr)
    self(obj->expr);
}

void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto func = irb.GetInsertBlock()->getParent();

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", func);
  auto endBb = llvm::BasicBlock::Create(mCtx, "if.end", func);
  auto elseBb = obj->else_
                  ? llvm::BasicBlock::Create(mCtx, "if.else", func)
                  : endBb;

  auto cond = emit_cond(obj->cond);
  irb.CreateCondBr(cond, thenBb, elseBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  if (!irb.GetInsertBlock()->getTerminator())
    irb.CreateBr(endBb);

  if (obj->else_) {
    irb.SetInsertPoint(elseBb);
    self(obj->else_);
    if (!irb.GetInsertBlock()->getTerminator())
      irb.CreateBr(endBb);
  }

  irb.SetInsertPoint(endBb);
}

void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;
  auto func = irb.GetInsertBlock()->getParent();

  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", func);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", func);
  auto endBb = llvm::BasicBlock::Create(mCtx, "while.end", func);

  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto cond = emit_cond(obj->cond);
  irb.CreateCondBr(cond, bodyBb, endBb);

  irb.SetInsertPoint(bodyBb);
  mLoopStack.push_back({ endBb, condBb });
  self(obj->body);
  mLoopStack.pop_back();
  if (!irb.GetInsertBlock()->getTerminator())
    irb.CreateBr(condBb);

  irb.SetInsertPoint(endBb);
}

void
EmitIR::operator()(DoStmt* obj)
{
  auto& irb = *mCurIrb;
  auto func = irb.GetInsertBlock()->getParent();

  auto bodyBb = llvm::BasicBlock::Create(mCtx, "do.body", func);
  auto condBb = llvm::BasicBlock::Create(mCtx, "do.cond", func);
  auto endBb = llvm::BasicBlock::Create(mCtx, "do.end", func);

  irb.CreateBr(bodyBb);
  irb.SetInsertPoint(bodyBb);
  mLoopStack.push_back({ endBb, condBb });
  self(obj->body);
  mLoopStack.pop_back();
  if (!irb.GetInsertBlock()->getTerminator())
    irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto cond = emit_cond(obj->cond);
  irb.CreateCondBr(cond, bodyBb, endBb);

  irb.SetInsertPoint(endBb);
}

void
EmitIR::operator()(BreakStmt* obj)
{
  auto& irb = *mCurIrb;
  ASSERT(!mLoopStack.empty());
  irb.CreateBr(mLoopStack.back().breakBb);
  auto deadBb = llvm::BasicBlock::Create(mCtx, "after.break", mCurFunc);
  irb.SetInsertPoint(deadBb);
}

void
EmitIR::operator()(ContinueStmt* obj)
{
  auto& irb = *mCurIrb;
  ASSERT(!mLoopStack.empty());
  irb.CreateBr(mLoopStack.back().continueBb);
  auto deadBb = llvm::BasicBlock::Create(mCtx, "after.continue", mCurFunc);
  irb.SetInsertPoint(deadBb);
}

void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;
  llvm::Value* retVal = nullptr;
  if (obj->expr)
    retVal = self(obj->expr);

  if (retVal)
    irb.CreateRet(retVal);
  else
    irb.CreateRetVoid();

  auto deadBb = llvm::BasicBlock::Create(mCtx, "after.return", mCurFunc);
  irb.SetInsertPoint(deadBb);
}

//==============================================================================
// 声明
//==============================================================================

void
EmitIR::operator()(Decl* obj)
{
  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);
  if (auto p = obj->dcst<VarDecl>())
    return self(p);
  ABORT();
}

void
EmitIR::operator()(VarDecl* obj)
{
  auto llty = self(obj->type);

  if (mCurFunc == nullptr) {
    // Global variable.
    llvm::Constant* init = nullptr;
    if (obj->init)
      init = emit_const(obj->type, obj->init);
    else
      init = llvm::Constant::getNullValue(llty);

    // Function declarations should never come through this branch.
    auto gv = new llvm::GlobalVariable(
      mMod, llty, obj->type->qual.const_, llvm::GlobalValue::ExternalLinkage,
      init, obj->name);
    obj->any = gv;
    return;
  }

  // Local variable.
  auto& irb = *mCurIrb;
  auto alloca = irb.CreateAlloca(llty, nullptr, obj->name);
  obj->any = alloca;

  if (obj->init)
    emit_init(alloca, obj->type, obj->init);
}

void
EmitIR::operator()(FunctionDecl* obj)
{
  // Reuse existing function if already declared (e.g. forward declarations
  // followed by definition).
  llvm::Function* func = mMod.getFunction(obj->name);
  if (!func) {
    auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));
    ASSERT(fty);
    func = llvm::Function::Create(
      fty, llvm::GlobalValue::ExternalLinkage, obj->name, mMod);
  }

  obj->any = func;

  if (obj->body == nullptr)
    return;

  // Map parameters to allocas (mimicking the O0 convention so we can take
  // their address).
  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);

  auto prevFunc = mCurFunc;
  mCurFunc = func;

  // Create allocas for parameters and copy in the incoming Args.
  ASSERT(obj->params.size() == func->arg_size());
  size_t i = 0;
  for (auto& arg : func->args()) {
    auto pdecl = obj->params[i++];
    auto pty = self(pdecl->type);
    // For array/pointer parameters the LLVM arg type is a pointer; store it
    // as a pointer in a `ptr` alloca.
    if (pdecl->type->texp &&
        (pdecl->type->texp->dcst<ArrayType>() ||
         pdecl->type->texp->dcst<PointerType>())) {
      pty = llvm::PointerType::get(mCtx, 0);
    }
    auto a = mCurIrb->CreateAlloca(pty, nullptr, pdecl->name);
    mCurIrb->CreateStore(&arg, a);
    pdecl->any = a;
  }

  // Translate body.
  self(obj->body);

  // Ensure the final block has a terminator.
  auto fty = func->getFunctionType();
  if (!mCurIrb->GetInsertBlock()->getTerminator()) {
    if (fty->getReturnType()->isVoidTy())
      mCurIrb->CreateRetVoid();
    else
      mCurIrb->CreateUnreachable();
  }

  mCurFunc = prevFunc;
}
